  @doc """
  Verifies that all `lookup/1` functions in `CA.SPE` return the exact same 
  binary string as the `title` field defined in the `spec/1` of `CA.Profile.Data`.
  
  Returns a list of tuples `{id, spec_title, lookup_title}` for any mismatches.
  """
  
  def verify_titles do
    CA.Profile.Data.specs()
    |> Enum.reduce([], fn %{id: id, title: title}, acc ->
      try do
        oid = oid(id)
        lookup_title = lookup(oid)

        if lookup_title != title do
          [{id, title, lookup_title} | acc]
        else
          acc
        end
      rescue
        _ -> [{id, title, :error} | acc]
      end
    end)
    |> Enum.reverse()
  end
end
